function s(e){const t=new Date(e),n={weekday:"short",day:"numeric",month:"short"};return t.toLocaleDateString("fr-FR",n)}function c(e){return new Date(e).toLocaleTimeString("fr-FR",{hour:"2-digit",minute:"2-digit"})}function u(e){return new Date(e).toLocaleDateString("fr-FR",{weekday:"short",day:"numeric",month:"short",hour:"2-digit",minute:"2-digit"})}function d(e){const t=new Date(e),n=t.getFullYear(),a=String(t.getMonth()+1).padStart(2,"0"),o=String(t.getDate()).padStart(2,"0"),r=String(t.getHours()).padStart(2,"0"),i=String(t.getMinutes()).padStart(2,"0");return`${n}-${a}-${o}T${r}:${i}`}export{s as a,d as b,u as c,c as f};
